import React from 'react';
import { 
  Box, 
  Typography, 
  Paper, 
  Button,
  alpha,
  useTheme 
} from '@mui/material';
import { styled } from '@mui/material/styles';
import { 
  AccountBalanceWallet, 
  AddCircleOutline, 
  Payment,
  ChevronRight 
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';

// Стили компонентов
const BalanceCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(2.5),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  marginBottom: theme.spacing(3),
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  background: `linear-gradient(135deg, ${alpha(theme.palette.primary.main, 0.08)} 0%, ${alpha(theme.palette.primary.dark, 0.05)} 100%)`,
  border: `1px solid ${alpha(theme.palette.primary.main, 0.1)}`,
  overflow: 'hidden',
  position: 'relative',
}));

const BalanceAmount = styled(Typography)(({ theme }) => ({
  fontWeight: 700,
  fontSize: '1.5rem',
  marginBottom: theme.spacing(0.5),
}));

const BalanceActions = styled(Box)(({ theme }) => ({
  display: 'flex',
  gap: theme.spacing(1),
  marginTop: theme.spacing(1.5),
}));

const QuickAction = styled(Button)(({ theme }) => ({
  borderRadius: theme.spacing(4),
  padding: theme.spacing(0.5, 2),
  fontWeight: 600,
  textTransform: 'none',
}));

const ActionButton = styled(Button)(({ theme }) => ({
  borderRadius: theme.spacing(6),
  padding: theme.spacing(1, 2),
  fontWeight: 600,
  textTransform: 'none',
}));

const WalletCircle = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: '-30px',
  right: '-30px',
  width: '100px',
  height: '100px',
  borderRadius: '50%',
  background: alpha(theme.palette.primary.main, 0.05),
  zIndex: 0,
}));

interface WalletWidgetProps {
  balance: number;
}

const WalletWidget: React.FC<WalletWidgetProps> = ({ balance }) => {
  const theme = useTheme();
  const navigate = useNavigate();
  
  const handleNavigateToWallet = () => {
    navigate('/wallet');
  };
  
  const handleTopUp = () => {
    navigate('/wallet');
  };
  
  const handleViewHistory = () => {
    navigate('/wallet');
  };
  
  return (
    <BalanceCard>
      <WalletCircle />
      <Box sx={{ position: 'relative', zIndex: 1 }}>
        <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
          Ваш баланс
        </Typography>
        <BalanceAmount>
          {balance.toLocaleString()} ₽
        </BalanceAmount>
        <BalanceActions>
          <QuickAction
            variant="contained"
            color="primary"
            size="small"
            startIcon={<AddCircleOutline />}
            onClick={handleTopUp}
          >
            Пополнить
          </QuickAction>
          <QuickAction
            variant="outlined"
            size="small"
            startIcon={<Payment />}
            onClick={handleViewHistory}
          >
            История
          </QuickAction>
        </BalanceActions>
      </Box>
      <ActionButton
        variant="text"
        color="primary"
        endIcon={<ChevronRight />}
        onClick={handleNavigateToWallet}
      >
        Кошелек
      </ActionButton>
    </BalanceCard>
  );
};

export default WalletWidget;
